const settings = $input.first().json;

// Current time IST (UTC+5:30)
const now = new Date();
const ist = new Date(now.getTime() + (5.5 * 60 * 60 * 1000));
const currentHour = ist.getUTCHours();
const currentMin  = ist.getUTCMinutes();
const currentTime = `${String(currentHour).padStart(2,'0')}:${String(currentMin).padStart(2,'0')}`;

// 20 minutes AFTER prayer time — ask did you pray?
const checkinOffset = 20;

const prayers = [
  { key: 'fajr',    name: 'Fajr',    emoji: '🌙', time: settings.fajr },
  { key: 'dhuhr',   name: 'Dhuhr',   emoji: '☀️', time: settings.dhuhr },
  { key: 'asr',     name: 'Asr',     emoji: '🌤', time: settings.asr },
  { key: 'maghrib', name: 'Maghrib', emoji: '🌇', time: settings.maghrib },
  { key: 'isha',    name: 'Isha',    emoji: '🌃', time: settings.isha },
];

let triggerPrayer = null;

for (const prayer of prayers) {
  if (!prayer.time) continue;
  const [pH, pM] = prayer.time.split(':').map(Number);
  let checkH = pH;
  let checkM = pM + checkinOffset;
  if (checkM >= 60) { checkH += 1; checkM -= 60; }
  const checkTime = `${String(checkH).padStart(2,'0')}:${String(checkM).padStart(2,'0')}`;
  if (checkTime === currentTime) {
    triggerPrayer = prayer;
    break;
  }
}

if (!triggerPrayer) return [];

console.log(`📋 Check-in time for ${triggerPrayer.name}`);
return [{ json: { prayer: triggerPrayer, currentTime } }];

const prayer = $('Check If Checkin Time').first().json.prayer;
const contacts = $input.all();

// Only contacts who have telegram AND subscribed to this prayer
const relevant = contacts.filter(item => {
  const c = item.json;
  if (!c.telegram_id || c.telegram_id.trim() === '') return false;
  const prayers = Array.isArray(c.prayers) ? c.prayers : JSON.parse(c.prayers || '[]');
  return prayers.some(p => p.toLowerCase() === prayer.name.toLowerCase());
});

console.log(`💌 Sending check-in to ${relevant.length} contacts for ${prayer.name}`);

if (!relevant.length) return [];

return relevant.map(item => ({
  json: {
    ...item.json,
    prayerName: prayer.name,
    prayerEmoji: prayer.emoji,
    prayerKey: prayer.key
  }
}));

